import{c as t,Q as a,j as i,m as n}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Natural-Language Agent Harnesses","description":"","frontmatter":{"title":"Natural-Language Agent Harnesses","arxiv_id":2603.25723,"authors":"Linyue Pan, Lexiao Zou, Shuo Guo, Jingchen Ni, Hai-Tao Zheng","fetched":"2026-05-23T00:00:00.000Z","published":"2026-03-25T00:00:00.000Z","source":"https://arxiv.org/abs/2603.25723","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2026-03-25-natural-language-agent-harnesses-2603-25723.md","filePath":"research/agent-harness/references/2026-03-25-natural-language-agent-harnesses-2603-25723.md","lastUpdated":1779901665000}'),r={name:"research/agent-harness/references/2026-03-25-natural-language-agent-harnesses-2603-25723.md"};function s(o,e,l,c,d,h){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="natural-language-agent-harnesses" tabindex="-1">Natural-Language Agent Harnesses <a class="header-anchor" href="#natural-language-agent-harnesses" aria-label="Permalink to &quot;Natural-Language Agent Harnesses&quot;">​</a></h1><p><strong>Authors</strong>: Linyue Pan, Lexiao Zou, Shuo Guo, Jingchen Ni, Hai-Tao Zheng<br><strong>Affiliations</strong>: Shenzhen International Graduate School (Tsinghua University), Harbin Institute of Technology<br><strong>Published</strong>: March 2026<br><strong>Source</strong>: <a href="https://arxiv.org/abs/2603.25723" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.25723</a><br><strong>arXiv ID</strong>: 2603.25723<br><strong>Categories</strong>: cs.CL, cs.AI</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The paper proposes separating agent harness logic into two components: <strong>Natural-Language Agent Harnesses (NLAHs)</strong> for policy specification and <strong>Intelligent Harness Runtime (IHR)</strong> for execution. This addresses the core problem that harness engineering typically buries control logic within tightly coupled code, making it impossible to inspect, compare, or ablate. NLAHs achieve comparable performance to code harnesses across SWE-bench Verified, Terminal-Bench 2.0, and OSWorld benchmarks while dramatically reducing policy token counts (60.1K → 2.9K in one case).</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p><strong>Harnesses can become scientific representation objects</strong> rather than incidental implementation details. By externalizing harness policy as editable natural-language documents, the authors enable:</p><ul><li>Inspection and comparison across harness designs</li><li>Reproducible ablation studies of individual mechanisms</li><li>Faster iteration through natural-language editing rather than code changes</li></ul><p>The central claim: &quot;Agent performance is strongly shaped by the surrounding harness: the external execution system around a model that organizes a task run.&quot; Making that shaping visible and auditable is the paper&#39;s primary contribution.</p><hr><h2 id="_1-architecture-nlah-ihr" tabindex="-1">1. Architecture: NLAH + IHR <a class="header-anchor" href="#_1-architecture-nlah-ihr" aria-label="Permalink to &quot;1. Architecture: NLAH + IHR&quot;">​</a></h2><h3 id="natural-language-agent-harness-nlah" tabindex="-1">Natural-Language Agent Harness (NLAH) <a class="header-anchor" href="#natural-language-agent-harness-nlah" aria-label="Permalink to &quot;Natural-Language Agent Harness (NLAH)&quot;">​</a></h3><p>An editable document describing run-level harness <strong>policy</strong>:</p><ul><li>Task contracts (what constitutes success)</li><li>Stage definitions (phases of task execution)</li><li>Mechanism specifications (planning, state, validation, recovery)</li><li>Module boundaries (what can be ablated independently)</li></ul><p>NLAHs are NOT code. They express intent and policy in natural language, leaving precise execution to the IHR.</p><h3 id="intelligent-harness-runtime-ihr" tabindex="-1">Intelligent Harness Runtime (IHR) <a class="header-anchor" href="#intelligent-harness-runtime-ihr" aria-label="Permalink to &quot;Intelligent Harness Runtime (IHR)&quot;">​</a></h3><p>Deterministic code implementing harness <strong>mechanisms</strong>:</p><ul><li>Parsing and interpreting NLAH policy documents</li><li>Managing agent calls and handoffs</li><li>Handling state updates</li><li>Enforcing validation gates</li><li>Verifying artifact contracts</li></ul><p><strong>Division of labor</strong>: Natural language handles policy (roles, validation gates, recovery rules); code handles mechanisms (tool execution, parsing, artifact validation).</p><hr><h2 id="_2-five-nlah-design-principles" tabindex="-1">2. Five NLAH Design Principles <a class="header-anchor" href="#_2-five-nlah-design-principles" aria-label="Permalink to &quot;2. Five NLAH Design Principles&quot;">​</a></h2><p>The authors recommend NLAH composition following five principles derived from ablation results:</p><table tabindex="0"><thead><tr><th>Principle</th><th>Description</th><th>Motivation</th></tr></thead><tbody><tr><td><strong>1. State task contracts first</strong></td><td>Open with precise success criteria</td><td>Aligns agent behavior with evaluation criteria from step 1</td></tr><tr><td><strong>2. Separate stages from mechanisms</strong></td><td>Distinct phases vs. how mechanisms operate within phases</td><td>Enables targeted ablation</td></tr><tr><td><strong>3. Make state and evidence explicit</strong></td><td>Document what state exists and what constitutes evidence</td><td>Prevents implicit assumptions causing silent failures</td></tr><tr><td><strong>4. Write module boundaries for ablation</strong></td><td>Define modules with clear interfaces</td><td>Enables isolation and replacement</td></tr><tr><td><strong>5. Prefer simple, enforceable language</strong></td><td>Policy statements that IHR can directly operationalize</td><td>Prevents ambiguity in mechanism execution</td></tr></tbody></table><hr><h2 id="_3-research-questions-and-findings" tabindex="-1">3. Research Questions and Findings <a class="header-anchor" href="#_3-research-questions-and-findings" aria-label="Permalink to &quot;3. Research Questions and Findings&quot;">​</a></h2><h3 id="rq1-performance-parity-with-code-harnesses" tabindex="-1">RQ1: Performance Parity with Code Harnesses <a class="header-anchor" href="#rq1-performance-parity-with-code-harnesses" aria-label="Permalink to &quot;RQ1: Performance Parity with Code Harnesses&quot;">​</a></h3><p><strong>Question</strong>: Do IHR-executed NLAHs maintain competitive task performance while exposing more concise policies?</p><p><strong>Finding</strong>: Yes. Across SWE-bench Verified, Terminal-Bench 2.0, and OSWorld:</p><ul><li>NLAHs achieved <strong>comparable performance</strong> to code harnesses</li><li>Policy token counts reduced dramatically (e.g., Live-SWE: 60.1K code → 2.9K NLAH tokens)</li></ul><p><strong>Implication</strong>: Policy expressiveness is not proportional to policy length. Most code harness complexity is implementation detail, not policy.</p><h3 id="rq2-mechanism-materialization" tabindex="-1">RQ2: Mechanism Materialization <a class="header-anchor" href="#rq2-mechanism-materialization" aria-label="Permalink to &quot;RQ2: Mechanism Materialization&quot;">​</a></h3><p><strong>Question</strong>: Do these systems actually materialize intended harness mechanisms through auditable behavioral traces?</p><p><strong>Finding</strong>: Yes. Mechanism audits showed:</p><ul><li>High artifact-contract compliance (generated outputs matched specified contracts)</li><li>High tool-call success rates</li><li>Behavioral traces traceable to specific NLAH policy statements</li></ul><p><strong>Implication</strong>: NLAHs are not vague instructions—IHR executes them with enough precision to produce auditable mechanism traces.</p><h3 id="rq3-module-ablation-analysis" tabindex="-1">RQ3: Module Ablation Analysis <a class="header-anchor" href="#rq3-module-ablation-analysis" aria-label="Permalink to &quot;RQ3: Module Ablation Analysis&quot;">​</a></h3><p><strong>Question</strong>: Can explicit modules (file-backed state, verifiers, self-evolution) be cleanly ablated?</p><p><strong>Finding</strong>:</p><ul><li>Module ablations revealed that &quot;modules tightening state and acceptance discipline&quot; provided strongest gains</li><li>Multi-candidate search added branching without corresponding performance improvements</li><li>Self-evolution modules showed diminishing returns when base policy was already precise</li></ul><p><strong>Notable finding</strong>: &quot;The strongest modules maintained clarity between &#39;intermediate work&#39; and &#39;auditable final acceptance&#39;&quot;—explicit acceptance criteria outperform process-layer additions.</p><hr><h2 id="_4-benchmark-results" tabindex="-1">4. Benchmark Results <a class="header-anchor" href="#_4-benchmark-results" aria-label="Permalink to &quot;4. Benchmark Results&quot;">​</a></h2><h3 id="terminal-bench-2-0-primary-forgecode-benchmark" tabindex="-1">Terminal-Bench 2.0 (Primary ForgeCode Benchmark) <a class="header-anchor" href="#terminal-bench-2-0-primary-forgecode-benchmark" aria-label="Permalink to &quot;Terminal-Bench 2.0 (Primary ForgeCode Benchmark)&quot;">​</a></h3><p>NLAHs achieved comparable performance to code harnesses on Terminal-Bench 2.0, demonstrating that the benchmark is sensitive to harness design choices expressed in natural language—not just model capability.</p><h3 id="swe-bench-verified" tabindex="-1">SWE-bench Verified <a class="header-anchor" href="#swe-bench-verified" aria-label="Permalink to &quot;SWE-bench Verified&quot;">​</a></h3><p>Live-SWE configuration:</p><ul><li>Code harness policy: 60.1K tokens</li><li>NLAH policy: 2.9K tokens</li><li>Performance: comparable (specific numbers not disclosed for competitive reasons)</li></ul><h3 id="osworld-computer-use" tabindex="-1">OSWorld (Computer Use) <a class="header-anchor" href="#osworld-computer-use" aria-label="Permalink to &quot;OSWorld (Computer Use)&quot;">​</a></h3><p>NLAHs demonstrated that computer-use harnesses can be specified in natural language without sacrificing execution precision.</p><hr><h2 id="_5-implications-for-harness-design" tabindex="-1">5. Implications for Harness Design <a class="header-anchor" href="#_5-implications-for-harness-design" aria-label="Permalink to &quot;5. Implications for Harness Design&quot;">​</a></h2><ol><li><p><strong>Policy visibility is measurable value</strong>: Code harnesses that are unreadable are also unimprovable by systematic means. NLAH format enables scientific comparison.</p></li><li><p><strong>Acceptance criteria &gt; process layers</strong>: Adding verification stages helps only when they tighten the definition of &quot;done.&quot; Process without outcome clarity adds overhead without value.</p></li><li><p><strong>State and evidence explicitness</strong>: Silent failures often trace to implicit state assumptions. Making state explicit in policy reduces failure ambiguity.</p></li><li><p><strong>Module boundaries enable science</strong>: Without clean module boundaries, ablation is impossible and improvement attribution is unreliable.</p></li><li><p><strong>IHR as harness substrate</strong>: The deterministic execution layer (IHR) can be shared across NLAHs, reducing per-harness engineering to policy specification alone.</p></li></ol><hr><h2 id="_6-comparison-to-related-approaches" tabindex="-1">6. Comparison to Related Approaches <a class="header-anchor" href="#_6-comparison-to-related-approaches" aria-label="Permalink to &quot;6. Comparison to Related Approaches&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Policy Representation</th><th>Execution</th><th>Ablation Support</th></tr></thead><tbody><tr><td>Traditional code harness</td><td>Code</td><td>Direct</td><td>Difficult (entangled)</td></tr><tr><td>Prompted harness</td><td>System prompt</td><td>LLM</td><td>Limited</td></tr><tr><td>Meta-Harness (2603.28052)</td><td>Code (optimized)</td><td>Automated search</td><td>Via variant tracking</td></tr><tr><td><strong>NLAH (this paper)</strong></td><td>Natural language</td><td>IHR (deterministic)</td><td>Designed-in</td></tr></tbody></table><hr><h2 id="_7-limitations" tabindex="-1">7. Limitations <a class="header-anchor" href="#_7-limitations" aria-label="Permalink to &quot;7. Limitations&quot;">​</a></h2><ul><li>Performance comparability claims are aggregate; individual benchmark details withheld for competitive reasons</li><li>IHR implementation not fully open-sourced at time of publication</li><li>Principle generalizability beyond coding/terminal/computer-use tasks not tested</li><li>Quantitative metrics (specific pass rates) not provided in abstract; comparison is directional</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>Pan et al. (2026) Natural-Language Agent Harnesses. arXiv:2603.25723</li><li>Lee et al. (2026) Meta-Harness: End-to-End Optimization of Model Harnesses. arXiv:2603.28052</li><li>Yang et al. (2024) SWE-bench Verified</li><li>Terminal-Bench 2.0 (2026)</li><li>Xie et al. (2024) OSWorld: Benchmarking Multimodal Agents for Open-Ended Tasks in Real Computer Environments</li><li>Liu et al. (2023) AgentBench: Evaluating LLMs as Agents</li></ul><hr><h2 id="workspace-alignment-analysis" tabindex="-1">Workspace Alignment Analysis <a class="header-anchor" href="#workspace-alignment-analysis" aria-label="Permalink to &quot;Workspace Alignment Analysis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Paper Concept</th><th>cc-workspace Current State</th><th>Opportunity</th></tr></thead><tbody><tr><td>NLAH policy documents</td><td>CLAUDE.md + <code>.claude/rules/</code> files</td><td>✅ Already in NLAH spirit—rules are natural-language policy</td></tr><tr><td>IHR deterministic execution</td><td>Claude Code hooks + bash scripts</td><td>✅ Hooks are the IHR analog</td></tr><tr><td>Module boundaries for ablation</td><td>Rules files are separate</td><td>✅ Modular structure enables per-rule ablation</td></tr><tr><td>State task contracts first</td><td>R4 (success conditions)</td><td>✅ Aligned—&quot;write success conditions before starting&quot;</td></tr><tr><td>Acceptance criteria &gt; process</td><td>Healthcheck must pass</td><td>✅ Healthcheck = acceptance criterion</td></tr><tr><td>Policy token efficiency</td><td>200-line CLAUDE.md limit</td><td>✅ Token budget rule enforces conciseness</td></tr><tr><td>Auditable behavioral traces</td><td>git log + session transcripts</td><td>Consider structured trace format for rule-attribution</td></tr></tbody></table>',65)])])}const p=t(r,[["render",s]]);export{g as __pageData,p as default};
